('VG-SUN-001', 'Vogue Butterfly Oversized', 'Glamorous butterfly sunglasses. Gradient lenses with UV protection.', 'e8f2bea6-7068-4c18-89f3-eb014a1d6da2', 'b265a223-a264-480d-97ac-cf785d6d4dab', 9999, 6999, 18, ARRAY['https://images.pexels.com/photos/1366919/pexels-photo-1366919.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['vogue','sunglasses','butterfly','oversized','women','gradient'], ARRAY['sunglasses','women','butterfly','oversized','fashion'], '{"frame_shape": "Butterfly", "material": "Acetate", "color": "Black", "gender": "Women", "size": "Large", "lens_type": "Gradient", "uv_protection": "UV400", "weight": "32g", "warranty": "2 Years"}', 85, 600),
