('VG-SUN-003', 'Vogue Cat Eye Sunglasses', 'Elegant cat-eye sunglasses with gradient lenses. Chic and feminine design.', 'e8f2bea6-7068-4c18-89f3-eb014a1d6da2', 'b265a223-a264-480d-97ac-cf785d6d4dab', 8999, 6499, 18, ARRAY['https://images.pexels.com/photos/1366919/pexels-photo-1366919.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/147641/pexels-photo-147641.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['vogue','sunglasses','cat-eye','women','gradient','elegant'], ARRAY['sunglasses','women','cat-eye','gradient','fashion'], '{"frame_shape": "Cat Eye", "material": "Acetate", "color": "Black", "gender": "Women", "size": "Medium", "lens_type": "Gradient", "uv_protection": "UV400", "weight": "28g", "warranty": "2 Years"}', 95, 650);
