('FT-SUN-003', 'Fastrack Wayfarer Black', 'Classic wayfarer sunglasses in black. Full UV protection. Unisex design.', '6b9e8785-a0ff-4e18-a8a1-3f215cd43296', 'c1562fe4-ee3e-40ca-a4af-be26402fbefa', 2999, 1999, 18, ARRAY['https://images.pexels.com/photos/701841/pexels-photo-701841.jpeg?auto=compress&cs=tinysrgb&w=600','https://images.pexels.com/photos/947885/pexels-photo-947885.jpeg?auto=compress&cs=tinysrgb&w=600'], true, false, ARRAY['fastrack','sunglasses','wayfarer','black','unisex','classic'], ARRAY['sunglasses','unisex','wayfarer','classic','value'], '{"frame_shape": "Wayfarer", "material": "Acetate", "color": "Black", "gender": "Unisex", "size": "Medium", "lens_type": "Standard", "uv_protection": "UV400", "weight": "30g", "warranty": "1 Year"}', 100, 650);
